const PANNATTI_DATA = [{"id": "nama1", "ten": "Danh chơn", "pali": "Vijjamāna-paññatti", "nhom": "nama", "mota": "Tên gọi đặt cho cái thật sự có (chân đế) — ví dụ gọi tên \"Tâm\", \"Sắc\", \"Tham\", \"Sân\" là danh từ chỉ thẳng pháp chân thật."}, {"id": "nama2", "ten": "Phi danh chơn", "pali": "Avijjamāna-paññatti", "nhom": "nama", "mota": "Tên gọi đặt cho cái không thật sự có theo nghĩa chân đế — ví dụ \"người\", \"núi\", \"xe\" — chỉ là khái niệm chế định do tưởng tượng ghép lại."}, {"id": "nama3", "ten": "Danh chơn phi danh chơn", "pali": "Vijjamānena avijjamāna-paññatti", "nhom": "nama", "mota": "Ghép tên gọi cái thật (chân đế) với cái không thật để chỉ một khái niệm — ví dụ \"lục thông\" (ghép \"lục\"-số thật với \"thông\"-khái niệm)."}, {"id": "nama4", "ten": "Phi danh chơn danh chơn", "pali": "Avijjamānena vijjamāna-paññatti", "nhom": "nama", "mota": "Ngược lại với mục trên — ghép cái không thật với cái thật để gọi tên một pháp chân đế — ví dụ \"Thiên nhãn thông\" (ghép khái niệm \"Thiên\" với \"nhãn\"-pháp thật)."}, {"id": "nama5", "ten": "Danh chơn danh chơn", "pali": "Vijjamānena vijjamāna-paññatti", "nhom": "nama", "mota": "Ghép hai tên gọi của pháp chân đế lại với nhau để chỉ một pháp chân đế khác — ví dụ \"Nhãn thức\" (ghép \"Nhãn\" và \"Thức\", đều là pháp thật)."}, {"id": "nama6", "ten": "Phi danh chơn phi danh chơn", "pali": "Avijjamānena avijjamāna-paññatti", "nhom": "nama", "mota": "Ghép hai tên gọi đều không phải pháp chân đế lại với nhau — ví dụ \"Quốc vương\" (ghép hai khái niệm chế định)."}, {"id": "attha1", "ten": "Hình thức", "pali": "Saṇṭhāna-paññatti", "nhom": "attha", "mota": "Khái niệm về hình dáng, dáng vẻ — như \"tròn\", \"vuông\", \"núi\", \"cây\" — do tưởng dựa trên sự sắp xếp của sắc pháp mà chế định ra."}, {"id": "attha2", "ten": "Hiệp thành", "pali": "Samūha-paññatti", "nhom": "attha", "mota": "Khái niệm về một tập hợp nhiều thành phần gộp lại — như \"cỗ xe\", \"ngôi nhà\", \"đoàn quân\"."}, {"id": "attha3", "ten": "Chúng sanh", "pali": "Satta-paññatti", "nhom": "attha", "mota": "Khái niệm về một \"chúng sinh\", \"con người\", \"cái tôi\" — do gộp chung ngũ uẩn lại mà chế định, không có thực thể chân đế đứng sau."}, {"id": "attha4", "ten": "Thời gian", "pali": "Kāla-paññatti", "nhom": "attha", "mota": "Khái niệm về thời gian — như \"sáng\", \"trưa\", \"năm\", \"tháng\" — do sự sinh diệt nối tiếp của các pháp mà chế định ra, bản thân thời gian không phải một pháp chân đế riêng."}, {"id": "attha5", "ten": "Hư không", "pali": "Ākāsa-paññatti", "nhom": "attha", "mota": "Khái niệm về khoảng trống, không gian — như khoảng trống trong hang, trong phòng — do không có sắc pháp hiện diện mà chế định ra."}, {"id": "attha6", "ten": "Phương hướng", "pali": "Disā-paññatti", "nhom": "attha", "mota": "Khái niệm về hướng — như \"đông\", \"tây\", \"nam\", \"bắc\" — do vị trí tương đối giữa các pháp mà chế định ra."}, {"id": "attha7", "ten": "Tiêu biểu", "pali": "Nimitta-paññatti", "nhom": "attha", "mota": "Khái niệm về hình ảnh, dấu hiệu làm đối tượng thiền định — như các loại nimitta (ánh sáng, hình ảnh) trong khi hành thiền chỉ (samatha)."}];
